namespace RecipeHub.Models;

public class RecipeService
{
    private readonly List<Recipe> _recipes;

    public RecipeService()
    {
        _recipes = new List<Recipe>
        {
            new() { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough, San Marzano tomatoes, Fresh mozzarella, Fresh basil, Olive oil, Salt", Steps = "1. Preheat oven to 475°F.\n2. Roll out dough on floured surface.\n3. Spread crushed tomatoes evenly.\n4. Add torn mozzarella pieces.\n5. Bake 10–12 minutes until crust is golden.\n6. Top with fresh basil and drizzle olive oil.", AverageRating = 4.5, RatingCount = 12 },
            new() { Id = 2, Title = "Spaghetti Carbonara", Category = "Italian", Ingredients = "Spaghetti, Guanciale, Eggs, Pecorino Romano, Black pepper", Steps = "1. Cook spaghetti in salted water.\n2. Crisp guanciale in a pan.\n3. Whisk eggs with grated pecorino and pepper.\n4. Toss hot pasta with guanciale.\n5. Remove from heat, stir in egg mixture.\n6. Serve immediately with extra pecorino.", AverageRating = 4.8, RatingCount = 20 },
            new() { Id = 3, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken thighs, Yogurt, Garam masala, Tomato sauce, Cream, Onion, Garlic, Ginger", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or bake chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomato sauce and garam masala.\n5. Simmer 15 minutes, add cream.\n6. Add chicken pieces and cook 5 more minutes.", AverageRating = 4.7, RatingCount = 15 },
            new() { Id = 4, Title = "Vegetable Pad Thai", Category = "Thai", Ingredients = "Rice noodles, Tofu, Bean sprouts, Peanuts, Lime, Tamarind paste, Fish sauce, Sugar, Eggs", Steps = "1. Soak rice noodles in warm water.\n2. Press and cube tofu, pan-fry until golden.\n3. Scramble eggs in the same pan.\n4. Add noodles with tamarind, fish sauce, and sugar.\n5. Toss with bean sprouts and tofu.\n6. Serve with crushed peanuts and lime wedge.", AverageRating = 4.3, RatingCount = 8 },
            new() { Id = 5, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef, Taco seasoning, Corn tortillas, Lettuce, Tomato, Cheese, Sour cream, Salsa", Steps = "1. Brown ground beef, drain fat.\n2. Add taco seasoning and water, simmer 5 minutes.\n3. Warm tortillas in a dry pan.\n4. Assemble with beef, lettuce, tomato, cheese.\n5. Top with sour cream and salsa.", AverageRating = 4.2, RatingCount = 10 },
            new() { Id = 6, Title = "Tom Yum Soup", Category = "Thai", Ingredients = "Shrimp, Lemongrass, Galangal, Kaffir lime leaves, Mushrooms, Chili paste, Fish sauce, Lime juice", Steps = "1. Boil water with lemongrass, galangal, and lime leaves.\n2. Add mushrooms and chili paste.\n3. Add shrimp, cook until pink.\n4. Season with fish sauce and lime juice.\n5. Serve hot, garnished with cilantro.", AverageRating = 4.6, RatingCount = 9 },
            new() { Id = 7, Title = "Guacamole", Category = "Mexican", Ingredients = "Avocados, Lime, Cilantro, Red onion, Jalapeño, Tomato, Salt", Steps = "1. Halve avocados and remove pit.\n2. Mash to desired consistency.\n3. Stir in diced onion, jalapeño, and tomato.\n4. Add lime juice, cilantro, and salt.\n5. Serve immediately with tortilla chips.", AverageRating = 4.4, RatingCount = 18 },
            new() { Id = 8, Title = "Butter Chicken", Category = "Indian", Ingredients = "Chicken, Butter, Tomato puree, Cream, Garam masala, Cumin, Garlic, Ginger, Fenugreek leaves", Steps = "1. Marinate chicken in yogurt and spices.\n2. Cook chicken in a hot pan.\n3. Make sauce: sauté garlic and ginger in butter.\n4. Add tomato puree and spices, simmer.\n5. Stir in cream and fenugreek leaves.\n6. Add chicken, simmer 10 minutes.", AverageRating = 4.9, RatingCount = 25 },
        };
    }

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount;
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round((totalStars + stars) / recipe.RatingCount, 1);
    }

    public void AddRecipe(RecipeSubmission submission)
    {
        var maxId = _recipes.Max(r => r.Id);
        _recipes.Add(new Recipe
        {
            Id = maxId + 1,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients,
            Steps = submission.Steps,
            AverageRating = 0,
            RatingCount = 0
        });
    }
}

