@page "/category/{CategoryName}"
@using RecipeHub.Models
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes - RecipeHub</PageTitle>

<nav><a href="/">← Back to Categories</a></nav>

<h1>@CategoryName Recipes</h1>

@if (recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="recipe-list">
        @foreach (var recipe in recipes)
        {
            <a href="/recipe/@recipe.Id" class="recipe-card">
                <h3>@recipe.Title</h3>
                <div class="recipe-meta">
                    <span class="stars">@(new string('★', (int)Math.Round(recipe.AverageRating)))@(new string('☆', 5 - (int)Math.Round(recipe.AverageRating)))</span>
                    <span>@recipe.AverageRating / 5</span>
                </div>
            </a>
        }
    </div>
}

