toolArgs.file_text:
@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Models
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<nav><a href="/">← Home</a></nav>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community.</p>

<EditForm Model="submission" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
    <DataAnnotationsValidator />
    <ValidationSummary />

    <div class="form-group">
        <label for="title">Recipe Title</label>
        <InputText id="title" @bind-Value="submission.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
        <ValidationMessage For="() => submission.Title" />
    </div>

    <div class="form-group">
        <label for="category">Category</label>
        <InputSelect id="category" @bind-Value="submission.Category" class="form-control">
            <option value="">-- Select a category --</option>
            @foreach (var cat in RecipeService.GetCategories())
            {
                <option value="@cat">@cat</option>
            }
        </InputSelect>
        <ValidationMessage For="() => submission.Category" />
    </div>

    <div class="form-group">
        <label for="ingredients">Ingredients (comma-separated)</label>
        <InputTextArea id="ingredients" @bind-Value="submission.Ingredients" class="form-control" rows="4"
                       placeholder="Flour, Sugar, Butter, Eggs, Apples, Cinnamon" />
        <ValidationMessage For="() => submission.Ingredients" />
    </div>

    <div class="form-group">
        <label for="steps">Steps (one per line)</label>
        <InputTextArea id="steps" @bind-Value="submission.Steps" class="form-control" rows="6"
                       placeholder="1. Preheat oven to 350°F.&#10;2. Mix dry ingredients.&#10;3. ..." />
        <ValidationMessage For="() => submission.Steps" />
    </div>

    <button type="submit" class="btn btn-primary">Submit Recipe</button>
</EditForm>

@code {
    private RecipeSubmission submission = new();

    private void HandleSubmit()
    {
        RecipeService.AddRecipe(submission);
        Navigation.NavigateTo($"/category/{submission.Category}");
    }
}

